  ('disabled-7c4986e7-moex-00220', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '若生產點落在生產可能曲線之內，表示：', '["資源有限，無法達到的產量組合", "資源未充分利用", "充分就業", "市場需求不足"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00221', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '近年來空氣污染日益嚴重，政府因而鼓勵民眾騎乘電動機車。然而電動機 車之供給與需求函數分別為Q=10P－75與Q=70－10P（其中價量之單位 分別為萬元與萬輛）。經專家評估最佳的電動機車數目為 10 萬輛，因此 政府應補貼供給者每輛多少元方能達到此一目標？', '["1.5萬元", "2萬元", "2.5萬元", "3萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00222', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '若某一消費者之效用函數為U（X,Y）=XY，其預算限制式為X+2Y=100。 此消費者效用極大化下之最適財貨組合為何？', '["X財貨25單位，Y財貨37.5單位", "X財貨50單位，Y財貨50單位", "X財貨50單位，Y財貨25單位", "X財貨100/3單位，Y財貨100/3單位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00223', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '若市場需求函數為P=100－Q，邊際成本函數為MC=10，則獨占廠商極大 化利潤下，下列敘述何者正確？', '["產量為50", "邊際收益為25", "總成本為450", "利潤為0"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00224', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '下列何者將導致市場生產無效率的數量？①競爭  ②外部成本與外部利', '["課稅", "僅", "", "僅"]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00225', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '假設一個自然獨占（naturalmonopoly）廠商採用邊際收益等於邊際成本來 決定其最適產量。下列何者正確？', '["此廠商的利潤為正值", "此廠商的利潤為零", "此廠商的利潤為負值", "資訊不足，無法判斷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL)
